Voici le code complet, à jour et sans erreur de SuperLoader.py intégrant toutes les fonctions (notamment load, call) et le correctif pour catalog_path_parts :
pythonCopierModifier# :name: SuperLoader
# :description: Charge dynamiquement une méthode, fonction ou objet depuis un catalogue JSON.
# :inputs: object_type (str), name (str)
# :outputs: objet Python correspondant
# :file: SuperLoader.py

import os
import json
import importlib

# On récupère la variable ROOT_PATH définie dans les builtins
try:
    ROOT_PATH = ROOT_PATH  # déjà injecté dans les builtins
except NameError:
    raise EnvironmentError("❌ ROOT_PATH n'est pas défini dans les builtins.")

def SuperLoader(object_type, name):
    """
    Charge dynamiquement une fonction, méthode ou objet défini dans un fichier JSON de catalogue.
    """
    if not object_type or not name:
        raise ValueError("❌ Les paramètres object_type et name sont requis.")

    # Construction du chemin vers le catalogue
    if object_type == "method":
        catalog_path_parts = [
            "objects", "system", "storage", "database", "resources", "json", "methods_catalog.json"
        ]
    elif object_type == "object":
        catalog_path_parts = [
            "objects", "system", "storage", "database", "resources", "json", "objects_catalog.json"
        ]
    elif object_type == "function":
        catalog_path_parts = [
            "objects", "system", "storage", "database", "resources", "json", "functions_catalog.json"
        ]
    else:
        raise ValueError(f"❌ Type d'objet non pris en charge : {object_type}")

    catalog_path = os.path.join(ROOT_PATH, *catalog_path_parts)

    if not os.path.exists(catalog_path):
        raise FileNotFoundError(f"❌ Catalogue introuvable : {catalog_path}")

    with open(catalog_path, "r", encoding="utf-8") as f:
        catalog = json.load(f)

    # Recherche du nom dans le catalogue
    match = next((entry for entry in catalog if entry.get("name") == name), None)

    if not match:
        raise ValueError(f"❌ Aucun objet nommé '{name}' trouvé dans le catalogue {object_type}.")

    if "path" not in match:
        raise KeyError(f"❌ Le champ 'path' est manquant pour '{name}' dans le catalogue {object_type}.")

    module_path = match["path"].replace("/", ".").rstrip(".py")

    try:
        module = importlib.import_module(module_path)
    except Exception as e:
        raise ImportError(f"❌ Module non trouvé ou erreur à l'import : {module_path}") from e

    if "function" in match:
        try:
            return getattr(module, match["function"])
        except AttributeError:
            raise AttributeError(f"❌ Fonction '{match['function']}' introuvable dans le module {module_path}.")
    else:
        return module

def load(object_type, name):
    return SuperLoader(object_type, name)

def call(object_type, name, *args, **kwargs):
    fonction = SuperLoader(object_type, name)
    return fonction(*args, **kwargs)


