Voici le fichier SuperLoader.py complet, à jour, et corrigé pour utiliser builtins.ROOT_PATH et non une variable non définie :
pythonCopierModifier# :name: SuperLoader
# :description: Charge dynamiquement des objets ou fonctions selon un catalogue JSON défini par type.
# :inputs: object_type (str), name (str)
# :outputs: objet ou fonction importée
# :type: function

import os
import json
import importlib
import builtins

def SuperLoader(object_type, name):
    catalog = load_catalog(object_type)
    entry = next((item for item in catalog if item["name"] == name), None)
    if not entry:
        raise ValueError(f"❌ Entrée '{name}' non trouvée dans le catalogue {object_type}.")

    module_path = entry["path"]
    if module_path.endswith(".py"):
        module_path = module_path[:-3]  # enlever .py si présent

    try:
        module = importlib.import_module(module_path)
    except Exception as e:
        raise ImportError(f"❌ Module non trouvé ou erreur à l'import : {module_path}") from e

    if entry.get("type") == "class":
        return getattr(module, name)
    elif entry.get("type") == "function":
        return getattr(module, name)
    else:
        return module  # on renvoie le module brut s’il ne s’agit ni d’une fonction ni d’une classe

def load_catalog(object_type):
    catalog_path = get_catalog_path(object_type)
    if not os.path.exists(catalog_path):
        raise FileNotFoundError(f"❌ Catalogue introuvable : {catalog_path}")
    with open(catalog_path, 'r') as f:
        return json.load(f)

def get_catalog_path(object_type):
    return os.path.join(
        builtins.ROOT_PATH,
        "system",
        "storage",
        "database",
        "resources",
        "json",
        f"{object_type}s_catalog.json"
    )

def load(object_type, name):
    return SuperLoader(object_type, name)

def call(object_type, name, *args, **kwargs):
    fonction = SuperLoader(object_type, name)
    return fonction(*args, **kwargs)


